@namespace sv_ef86d13073594e23aa0e2cf24c8dd977.Components.Pages

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button">
    <div class="card-img-top product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         style="height: 180px;">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-2 text-warning">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2 align-self-start">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

@page "/catalog"
@using sv_ef86d13073594e23aa0e2cf24c8dd977
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <div class="row">
        @* ───── Left sidebar: filters ───── *@
        <aside class="col-lg-3 col-md-4 mb-3">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @* Category checkboxes *@
                    <h6>Category</h6>
                    @if (categories is not null)
                    {
                        @foreach (var cat in categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                       checked="@selectedCategories.Contains(cat)"
                                       @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted small">Loading…</p>
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Min Price</label>
                        <input type="number" class="form-control form-control-sm"
                               min="0" step="0.01"
                               @bind="minPrice" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Max Price</label>
                        <input type="number" class="form-control form-control-sm"
                               min="0" step="0.01"
                               @bind="maxPrice" />
                    </div>

                    <hr />

                    @* In-stock toggle *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
                    </div>
                </div>
            </div>
        </aside>

        @* ───── Main content area ───── *@
        <main class="col-lg-9 col-md-8">
            @if (errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">
                    <strong>Error:</strong> @errorMessage
                </div>
            }
            else if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (result is null || result.Items.Count == 0)
            {
                <div class="alert alert-info text-center mt-3" role="alert">
                    No products found. Try adjusting your filters.
                </div>
            }
            else
            {
                @* Toolbar *@
                <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                    <div class="d-flex align-items-center gap-2">
                        <label class="form-label mb-0 fw-bold small">Sort by:</label>
                        <select class="form-select form-select-sm" style="width: auto;"
                                @onchange="OnSortChanged">
                            @foreach (var opt in sortOptions)
                            {
                                <option value="@opt.Value" selected="@(sortBy == opt.Value)">@opt.Label</option>
                            }
                        </select>
                    </div>
                    <span class="text-muted small">
                        Showing @(firstItem)–@(lastItem) of @(result.TotalCount) products
                    </span>
                </div>

                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                    @foreach (var product in result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="HandleProductSelected"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (totalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center flex-wrap">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                        disabled="@(currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @foreach (var p in GetPageNumbers())
                            {
                                <li class="page-item @(p == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                        disabled="@(currentPage == totalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
</div>

@code {
    // ── Filter state ──
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // ── Sort / paging ──
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    // ── Results ──
    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    // ── Sort options ──
    private static readonly (string Value, string Label)[] sortOptions =
    {
        ("price_asc",  "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc",   "Name: A-Z"),
        ("rating_desc","Rating: Highest"),
    };

    // ── Computed helpers ──
    private int totalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int firstItem => result is null || result.Items.Count == 0
        ? 0
        : (result.Page - 1) * PageSize + 1;

    private int lastItem => result is null
        ? 0
        : (result.Page - 1) * PageSize + result.Items.Count;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            if (categories is null)
            {
                categories = await ProductService.GetCategoriesAsync();
            }

            var filter = BuildFilter();
            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private ProductFilter BuildFilter()
    {
        return new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
    }

    // ── Filter actions ──

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadDataAsync();
    }

    // ── Sort ──

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await LoadDataAsync();
    }

    // ── Pagination ──

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages || page == currentPage) return;
        currentPage = page;
        await LoadDataAsync();
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (totalPages <= maxVisible)
            return Enumerable.Range(1, totalPages);

        var start = Math.Max(1, currentPage - maxVisible / 2);
        var end = Math.Min(totalPages, start + maxVisible - 1);
        if (end - start + 1 < maxVisible)
            start = Math.Max(1, end - maxVisible + 1);

        return Enumerable.Range(start, end - start + 1);
    }

    // ── Card callbacks ──

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder – wire up cart logic here
        return Task.CompletedTask;
    }
}

